// 1. Grab the client rows from the "Read Clients" node
const items = $input.all(); 
const today = new Date();
today.setHours(0, 0, 0, 0);

// 2. Grab Settings from the "Read Settings" node
const settingsItems = $items("Read Settings");
const config = settingsItems[0].json; 

// 3. Set global variables from spreadsheet
const BUSINESS_NAME = config['Business Name'];
const PENALTY_PERCENTAGE = config['Penalty Percentage'];
const PENALTY_RATE = Number(PENALTY_PERCENTAGE) / 100;

for (const item of items) {
  const row = item.json;

  // 4. Safety check: skip empty rows
  if (!row['Status'] || !row['Due Date'] || !row['Amount']) {
      row.Action = 'None';
      continue;
  }
// 4.1 Phone number check
  // --- NEW: Phone Number Sanitization ---
  if (row['Phone Number']) {
      // 1. Convert to string and remove any spaces, dashes, or "+" 
      let cleanNumber = row['Phone Number'].toString().replace(/\D/g, '');

      // 2. If it's 10 digits (e.g., 9980540190), add 91
      if (cleanNumber.length === 10) {
          cleanNumber = '91' + cleanNumber;
      }
      // 3. If it's 12 digits but doesn't start with 91, fix it (for other country codes if needed)
      // Or if it's 12 digits and starts with 91, it's already perfect.

      row['Phone Number'] = cleanNumber;
  }
  // 5. Skip if already paid or archived
  if (row.Status.toLowerCase() === 'paid' || row.Status.toLowerCase() === 'archived') {
    row.Action = 'None';
    continue;
  }

  // 6. Clean the amount for math
  row.Amount = Number(row.Amount.toString().replace(/,/g, ''));

  // 7. Parse the Due Date
  const dueDate = new Date(row['Due Date']);
  dueDate.setHours(0, 0, 0, 0);

  // 8. Format Date to DD-MM-YYYY
  const d = dueDate.getDate().toString().padStart(2, '0');
  const m = (dueDate.getMonth() + 1).toString().padStart(2, '0');
  const y = dueDate.getFullYear();
  row['Formatted Date'] = `${d}-${m}-${y}`;

  // 9. Calculate Day Difference
  const diffTime = dueDate.getTime() - today.getTime();
  const diffDays = Math.round(diffTime / (1000 * 60 * 60 * 24));

  // 10. Routing Logic
  if (diffDays <= 5 && diffDays > 0) {
    row.Action = 'Send Warning';
    row['Days Late'] = 0; 
  } 
  else if (diffDays === 0) {
    row.Action = 'Send Due Today Notice';
    row['Days Late'] = 0; 
  } 
  else if (diffDays < 0) {
    row.Action = 'Send Escalation';
    row['Days Late'] = Math.abs(diffDays); 
  } 
  else {
    row.Action = 'None';
    row['Days Late'] = 0;
  }

  // 11. Math with Dynamic Penalty Rate
  row['Daily Fine'] = Math.round(row.Amount * PENALTY_RATE);
  row['Total Fine'] = row['Daily Fine'] * row['Days Late'];
  row['Total Payable'] = row.Amount + row['Total Fine'];

  // 12. Indian Currency Formatting (Commas)
  row['Formatted Amount'] = row.Amount.toLocaleString('en-IN');
  row['Formatted Daily Fine'] = row['Daily Fine'].toLocaleString('en-IN');
  row['Formatted Total Fine'] = row['Total Fine'].toLocaleString('en-IN');
  row['Formatted Total Payable'] = row['Total Payable'].toLocaleString('en-IN');

 // 13. DOUBLE-FORMATTER (Dynamic Templates with Name Matching)
  if (row.Action !== 'None') {
      // This converts "Send Warning" into "Warning Template" to match your headers
      let actionName = row.Action.replace('Send ', ''); 
      let templateKey = actionName + ' Template';

      let template = config[templateKey] || "";

      if (template === "") {
          row['WhatsApp_Body'] = `Error: Could not find [${templateKey}] in Settings`;
          row['Email_Body'] = `Error: Could not find [${templateKey}] in Settings`;
      } else {
// --- Build the WhatsApp Message ---
      let waMessage = template;

      // 1. Convert HTML tags to WhatsApp formatting
      waMessage = waMessage.replace(/<br>/g, '\n'); // Line breaks
      waMessage = waMessage.replace(/<b>/g, '*');   // Bold start
      waMessage = waMessage.replace(/<\/b>/g, '*'); // Bold end

      // 2. Map variables (Ensure we use WhatsApp's * symbol here too)
      waMessage = waMessage.replace(/\[NAME\]/g, row['Client Name'] || "Customer");
      waMessage = waMessage.replace(/\[BUSINESS_NAME\]/g, BUSINESS_NAME || "");
      waMessage = waMessage.replace(/\[CHANNEL\]/g, 'WhatsApp message'); 
      waMessage = waMessage.replace(/\[AMOUNT\]/g, `*₹${row['Formatted Amount']}*`);
      waMessage = waMessage.replace(/\[DATE\]/g, `*${row['Formatted Date']}*`);
      waMessage = waMessage.replace(/\[DAYS\]/g, `*${row['Days Late']}*`);
      waMessage = waMessage.replace(/\[PENALTY_PERCENTAGE\]/g, PENALTY_PERCENTAGE || "0");
      waMessage = waMessage.replace(/\[DAILY_FINE\]/g, `*₹${row['Formatted Daily Fine']}*`);
      waMessage = waMessage.replace(/\[TOTAL_FINE\]/g, `*₹${row['Formatted Total Fine']}*`);
      waMessage = waMessage.replace(/\[TOTAL\]/g, `*₹${row['Formatted Total Payable']}*`);
      row['WhatsApp_Body'] = waMessage;

      // --- Build the Email Message ---
      let emailMessage = template;
      emailMessage = emailMessage.replace(/\n/g, '<br>'); // Convert new lines to HTML

      // The email already understands <b> tags, so no extra replacement needed for tags!

      emailMessage = emailMessage.replace(/\[NAME\]/g, row['Client Name'] || "Customer");
      emailMessage = emailMessage.replace(/\[BUSINESS_NAME\]/g, BUSINESS_NAME || "");
      emailMessage = emailMessage.replace(/\[CHANNEL\]/g, 'E-mail'); 
      emailMessage = emailMessage.replace(/\[AMOUNT\]/g, `<b>₹${row['Formatted Amount']}</b>`);
      emailMessage = emailMessage.replace(/\[DATE\]/g, `<b>${row['Formatted Date']}</b>`);
      emailMessage = emailMessage.replace(/\[DAYS\]/g, `<b>${row['Days Late']}</b>`);
      emailMessage = emailMessage.replace(/\[PENALTY_PERCENTAGE\]/g, PENALTY_PERCENTAGE || "0");
      emailMessage = emailMessage.replace(/\[DAILY_FINE\]/g, `<b>₹${row['Formatted Daily Fine']}</b>`);
      emailMessage = emailMessage.replace(/\[TOTAL_FINE\]/g, `<b>₹${row['Formatted Total Fine']}</b>`);
      emailMessage = emailMessage.replace(/\[TOTAL\]/g, `<b>₹${row['Formatted Total Payable']}</b>`);
      row['Email_Body'] = emailMessage;
      }
  }
}

return items;
